#include<bits/stdc++.h>
using namespace std;
int f[210][20010],n,k,q[20010];
struct node
{
    int l,p,s;
    bool operator<(const node&b)const
    {
        return s<b.s;
    }
}a[110];
int main()
{
    scanf("%d%d",&n,&k);
    for(int i=1;i<=k;i++)
    {
        scanf("%d%d%d",&a[i].l,&a[i].p,&a[i].s);
    }
    sort(a+1,a+1+k);
    for(int i=1;i<=k;i++)
    {
        int h=1,t=1;
        for(int j=1;j<=n;j++)
        {
            f[i][j]=max(f[i-1][j],f[i][j-1]);
            if(j>=a[i].s+a[i].l)
            {
                continue;
            }
            while(h<=t&&q[h]+a[i].l<j)
            {
                h++;
            }
            if(j<a[i].s)
            {
                while(h<=t&&f[i-1][q[t]]-q[t]*a[i].p<=f[i-1][j]-j*a[i].p)
                {
                    t--;
                }
                q[++t]=j;
            }
            else
            {
                f[i][j]=max(f[i][j],f[i-1][q[h]]+(j-q[h])*a[i].p);
            }
        }
    }
    printf("%d",f[k][n]);
    return 0;
}
